import 'dart:async';import 'package:bookly/Core/Utils/Entities/book_entities.dart';import 'package:connectivity_plus/connectivity_plus.dart';import 'package:flutter_bloc/flutter_bloc.dart';part 'main_state.dart';class MainCubit extends Cubit<MainState> {  static MainCubit get(context) => BlocProvider.of(context);  final Connectivity _connectivity;  late StreamSubscription<ConnectivityResult> _subscription;  MainCubit(this._connectivity) : super(ConnectivityLoading()) {    _subscription = _connectivity.onConnectivityChanged.listen((result) {      if (result == ConnectivityResult.none) {        emit(ConnectivityDisconnected());      } else {        emit(ConnectivityConnected());      }    });  }  @override  Future<void> close() {    _subscription.cancel();    return super.close();  }  List<BookEntities> listOfBookMaps = [];  int listOfBookMapsLen = 0;  void addBookMap(BookEntities bookMap) {    listOfBookMaps.add(bookMap);    listOfBookMapsLen = listOfBookMaps.length;    emit(ConnectivityConnected());  }}